  ('social-worker-moex-02015', 'social-worker', 'social-worker-moex-107-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '1989 年為了讓「兒童權利宣言」能具備拘束力，聯合國大會乃通過「兒童權利公約」對各締約國具有法 令的約束力。該公約提出四項普遍性的指導原則，下列何者錯誤？', '["禁止歧視原則", "兒童最佳利益", "生存與發展權", "福利與受教權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5659ee27e44f", "answer_pdf_sha1": "7fe5f1f09f6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
